package com.example.sharehandler

import android.content.Intent
import android.graphics.Bitmap
import android.net.Uri
import android.os.Bundle
import android.provider.MediaStore
import android.util.Log
import androidx.appcompat.app.AppCompatActivity
import java.io.IOException

class ShareHandlerActivity : AppCompatActivity() {
    private val TAG = "ShareHandlerActivity"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        val intent = intent
        val action = intent.action
        val type = intent.type
        
        if (Intent.ACTION_SEND == action && type != null) {
            if ("text/plain" == type) {
                handleSendText(intent)
            } else if (type.startsWith("image/")) {
                handleSendImage(intent)
            }
        } else if (Intent.ACTION_SEND_MULTIPLE == action && type != null) {
            if (type.startsWith("image/")) {
                handleSendMultipleImages(intent)
            }
        }
        
        finish()
    }
    
    private fun handleSendText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        if (sharedText != null) {
            Log.d(TAG, "Received text: $sharedText")
            // Process the shared text (URL or plain text)
            processSharedContent(sharedText)
        }
    }
    
    private fun handleSendImage(intent: Intent) {
        val uri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        if (uri != null) {
            Log.d(TAG, "Received image URI: $uri")
            try {
                val bitmap = MediaStore.Images.Media.getBitmap(contentResolver, uri)
                processSharedImage(bitmap)
            } catch (e: IOException) {
                Log.e(TAG, "Error processing image", e)
            }
        }
    }
    
    private fun handleSendMultipleImages(intent: Intent) {
        val uris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
        if (uris != null) {
            for (uri in uris) {
                Log.d(TAG, "Received multiple image URI: $uri")
                try {
                    val bitmap = MediaStore.Images.Media.getBitmap(contentResolver, uri)
                    processSharedImage(bitmap)
                } catch (e: IOException) {
                    Log.e(TAG, "Error processing image", e)
                }
            }
        }
    }
    
    private fun processSharedContent(content: String) {
        // Extract URL from text if present
        val urlRegex = Regex("https?://[\\w\\.-]+(?:/[\\w/\\.-]*)?\\??[\\w\\.-&=%]*")
        val urls = urlRegex.findAll(content)
        
        if (urls.any()) {
            urls.forEach { matchResult ->
                val url = matchResult.value
                Log.d(TAG, "Extracted URL: $url")
                // Handle URL processing here
            }
        } else {
            Log.d(TAG, "Received plain text: $content")
            // Handle plain text processing here
        }
    }
    
    private fun processSharedImage(bitmap: Bitmap) {
        Log.d(TAG, "Processing shared image with dimensions: ${bitmap.width}x${bitmap.height}")
        // Handle image processing here
    }
}